external_knowledge:
- 'shining stars' refers to the top 3 publications;
- 'brightness' refers to the impact factor of the publications;
- 'department' refers to the academic or research department.

sql:
SELECT title
FROM publications
WHERE type = 'Journal' AND impact_factor > (SELECT AVG(impact_factor) FROM publications WHERE type = 'Journal');

